    public static keys(key: number | string): KeyPair
    {
        if (WK._keys.length === 0)
            WK.make();

        if (typeof key === "number")
        {
            if ((key >= 0) && (key < WK._keys.length))
                return WK._keys[key];
            else {
                console.error("Can't found KeyPair in WK");
                process.exit(1);
            }
        }
        else
        {
            let keypair = WK._map.get(key);
            if (keypair !== undefined)
                return keypair;
            else {
                console.error("Can't found KeyPair in WK");
                process.exit(1);
            }
        }
    }

